solutionCode:
Add FormProvider to the react-hook-form import. In SearchForm, wrap SearchFormFields with FormProvider passing the methods object:

import { useForm, useFormContext, Controller, FormProvider } from 'react-hook-form';

// Inside SearchForm return:
return (
  <form onSubmit={methods.handleSubmit(onSubmitForm)} className="card" role="search" aria-label="Flight search">
    <FormProvider {...methods}>
      <SearchFormFields />
    </FormProvider>
    <button type="submit" className="btn btn-primary">
      Search Flights
    </button>
  </form>
);
